package main

import (
	"errors"
	"fmt"
)

// EvaluationError wraps an error with evaluation context
type EvaluationError struct {
	err           error
	NamespaceKey  string
	FlagKey       string
	Phase         string
}

// Error implements the error interface
func (e *EvaluationError) Error() string {
	return fmt.Sprintf("error during evaluation phase %q (namespace: %q, flag: %q): %v", e.Phase, e.NamespaceKey, e.FlagKey, e.err)
}

// Unwrap returns the wrapped error
func (e *EvaluationError) Unwrap() error {
	return e.err
}

func main() {
	// Test error wrapping
	baseErr := fmt.Errorf("sql: no rows in result set")
	wrappedErr := &EvaluationError{
		err:          baseErr,
		NamespaceKey: "production",
		FlagKey:      "feature-x",
		Phase:        "fetching flag",
	}

	fmt.Println("Error message:")
	fmt.Println(wrappedErr.Error())
	fmt.Println()

	// Test Unwrap
	fmt.Println("Unwrapped error:", errors.Unwrap(wrappedErr))
	fmt.Println()

	// Test Is/As functionality
	if errors.Is(wrappedErr, baseErr) {
		fmt.Println("✓ errors.Is() works: can find original error")
	}

	var ee *EvaluationError
	if errors.As(wrappedErr, &ee) {
		fmt.Println("✓ errors.As() works: can extract EvaluationError")
		fmt.Println("  - Namespace:", ee.NamespaceKey)
		fmt.Println("  - Flag:", ee.FlagKey)
		fmt.Println("  - Phase:", ee.Phase)
	}
}
EOF
go run /tmp/test_errors.go

